<title>Searchlight Showdown</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Archivo+Black&family=DM+Mono:wght@400;500&family=Fraunces:opsz,wght@9..144,600;9..144,800&display=swap');
:root{--ink:#130e13;--paper:#f5ebd7;--hot:#ff3d20;--sun:#ffce3a;--cyan:#43d5e6;--muted:#725e5d}*{box-sizing:border-box}body{margin:0;min-height:100vh;color:var(--ink);background:radial-gradient(circle at 13% 10%,#fff5b7 0 2px,transparent 3px),radial-gradient(circle at 85% 22%,#fff5b7 0 1px,transparent 2px),#19111b;background-size:29px 29px,41px 41px;font-family:'DM Mono',monospace}.wrap{max-width:960px;margin:auto;padding:24px 18px 46px}.mast{display:flex;justify-content:space-between;align-items:flex-end;color:var(--paper);gap:12px;margin:8px 0 18px}.eyebrow{font-size:.68rem;letter-spacing:.15em;color:var(--sun);margin:0 0 8px}.mast h1{font:800 clamp(2.3rem,7vw,5.4rem)/.84 'Archivo Black',sans-serif;letter-spacing:-.07em;margin:0;text-transform:uppercase}.tag{font-size:.72rem;max-width:17rem;line-height:1.45;color:#dacdd0}.arena{overflow:hidden;position:relative;background:var(--paper);border:4px solid var(--ink);box-shadow:8px 8px 0 var(--hot)}.ticker{white-space:nowrap;overflow:hidden;background:var(--hot);color:white;font-size:.71rem;letter-spacing:.12em;padding:9px 0}.ticker span{display:inline-block;animation:scroll 16s linear infinite}.controls{padding:26px clamp(16px,5vw,48px) 16px;background:linear-gradient(105deg,#f6ddb0,#f9f0df 60%,#d8fbf7)}.controls h2{font:800 clamp(1.3rem,3vw,2.2rem)/1 'Fraunces',serif;margin:0 0 8px}.hint{color:var(--muted);font-size:.78rem;line-height:1.5;margin:0 0 20px}.inputs{display:grid;grid-template-columns:1fr auto 1fr;gap:10px;align-items:center}.vs{font:800 1.2rem 'Archivo Black',sans-serif;background:var(--sun);border:2px solid var(--ink);border-radius:50%;width:42px;height:42px;display:grid;place-items:center;transform:rotate(-8deg)}input{min-width:0;width:100%;border:2px solid var(--ink);border-radius:0;background:#fffaf0;padding:14px 12px;font:500 1rem 'DM Mono';outline:none;box-shadow:3px 3px 0 var(--ink)}input:focus{box-shadow:4px 4px 0 var(--cyan)}.launch{margin-top:18px;display:flex;gap:12px;align-items:center;flex-wrap:wrap}.launch button{cursor:pointer;border:2px solid var(--ink);background:var(--hot);color:white;padding:13px 19px;font:800 .83rem 'Archivo Black';letter-spacing:.06em;box-shadow:4px 4px 0 var(--ink)}.launch button:hover{transform:translate(2px,2px);box-shadow:2px 2px 0 var(--ink)}.random{font-size:.72rem;color:var(--muted);cursor:pointer;text-decoration:underline;text-underline-offset:3px}.stage{display:none;padding:24px clamp(16px,5vw,48px) 34px;background:#f7ecd9}.stage.live{display:block;animation:appear .35s ease-out}.scan{height:7px;background:repeating-linear-gradient(90deg,var(--cyan) 0 12px,var(--ink) 12px 16px);margin-bottom:22px;animation:scan 1.5s linear infinite}.fighters{display:grid;grid-template-columns:1fr auto 1fr;gap:13px;align-items:end}.fighter{text-align:center;min-width:0}.fighter .name{font:800 clamp(1rem,3vw,1.55rem)/1 'Fraunces',serif;overflow-wrap:anywhere;margin-bottom:9px}.meter{height:clamp(105px,24vw,210px);border:3px solid var(--ink);background:repeating-linear-gradient(0deg,transparent 0 19px,#cfbfaa 20px);display:flex;align-items:flex-end;padding:6px}.bar{width:100%;height:0;background:var(--hot);border:2px solid var(--ink);transition:height 1.1s cubic-bezier(.18,.89,.32,1.2)}.fighter.right .bar{background:var(--cyan)}.versus{font:800 clamp(2rem,7vw,5rem)/1 'Archivo Black';color:var(--hot);text-shadow:3px 3px 0 var(--ink);padding-bottom:20px}.numbers{font-size:clamp(.8rem,2.4vw,1.05rem);margin-top:10px;min-height:1.3em}.verdict{margin:27px auto 0;max-width:600px;border-top:2px solid var(--ink);padding-top:18px;text-align:center;font:600 1.08rem/1.35 'Fraunces',serif}.winner{color:var(--hot);font-family:'Archivo Black';letter-spacing:-.04em}.footer{color:#ebdedd;text-align:center;font-size:.72rem;line-height:1.5;margin:24px auto 0;max-width:600px}.footer a{color:var(--sun)}.spark{position:absolute;width:12px;height:12px;background:var(--sun);border:2px solid var(--ink);transform:rotate(45deg);opacity:.8}.s1{left:8%;top:48%}.s2{right:5%;bottom:15%;background:var(--cyan)}@keyframes scroll{from{transform:translateX(0)}to{transform:translateX(-50%)}}@keyframes scan{to{background-position:180px 0}}@keyframes appear{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:none}}@media(max-width:520px){.mast{align-items:flex-start;flex-direction:column}.tag{max-width:28rem}.inputs{grid-template-columns:1fr;gap:9px}.vs{margin:auto}.fighters{gap:7px}.versus{padding-bottom:15px}.controls{padding-top:23px}}
</style>
</head>
<body>
<main class="wrap">
 <header class="mast"><div><p class="eyebrow">A TINY INTERNET SPECTATOR SPORT</p><h1>Searchlight<br>Showdown</h1></div><p class="tag">Choose two ideas. The arena gives them a gloriously unscientific bout.</p></header>
 <section class="arena" aria-labelledby="fight-title"><div class="ticker"><span>✦ LIVE FROM THE INDEX ✦ OPINIONATED MATH ✦ NO ALGORITHMS WERE HARMED ✦ &nbsp;&nbsp; ✦ LIVE FROM THE INDEX ✦ OPINIONATED MATH ✦ NO ALGORITHMS WERE HARMED ✦</span></div>
 <div class="controls"><h2 id="fight-title">What should face off?</h2><p class="hint">This is a playful popularity duel, not a live search. Choose words that deserve a tiny brass bell and an audience.</p><div class="inputs"><input id="left" maxlength="34" value="Knight Rider" aria-label="First contender"><div class="vs">VS</div><input id="right" maxlength="34" value="Zelda" aria-label="Second contender"></div><div class="launch"><button id="go">RING THE BELL →</button><span class="random" id="random">give me a weird pairing</span></div></div>
 <div class="stage" id="stage" aria-live="polite"><div class="scan"></div><div class="fighters"><div class="fighter"><div class="name" id="nameA"></div><div class="meter"><div class="bar" id="barA"></div></div><div class="numbers" id="scoreA"></div></div><div class="versus">VS</div><div class="fighter right"><div class="name" id="nameB"></div><div class="meter"><div class="bar" id="barB"></div></div><div class="numbers" id="scoreB"></div></div></div><p class="verdict" id="verdict"></p></div><i class="spark s1"></i><i class="spark s2"></i>
 </section>
 <p class="footer">Inspired by Jon’s <a href="<?= htmlspecialchars($sourceUrl) ?>">“Google Fight : Make a fight with Googlefight”</a> post, a splendid relic from when the web was allowed to be strange for the sake of strange.</p>
</main>
<script>
const pairs=[['Mario Kart','a very serious nap'],['Poutine','fish and chips'],['a T. rex','a shopping cart'],['The Hobbit','a really good sandwich'],['Lego','cardboard boxes'],['a moon base','a treehouse'],['sword fighting','a spelling bee'],['dragon fruit','a mechanical keyboard']];
const $=s=>document.querySelector(s), fmt=n=>n.toLocaleString('en-US');
function hash(s){let h=2166136261;for(let i=0;i<s.length;i++)h=Math.imul(h^s.charCodeAt(i),16777619);return h>>>0}
function duel(){const a=$('#left').value.trim()||'Mystery A',b=$('#right').value.trim()||'Mystery B';const seed=hash(a.toLowerCase()+'|'+b.toLowerCase());const total=80000+(seed%850000);let share=34+((seed>>>8)%33);if(a.toLowerCase()===b.toLowerCase())share=50;const A=Math.round(total*share/100),B=total-A;$('#nameA').textContent=a;$('#nameB').textContent=b;$('#scoreA').textContent='';$('#scoreB').textContent='';$('#barA').style.height='0';$('#barB').style.height='0';$('#stage').classList.add('live');setTimeout(()=>{$('#barA').style.height=share+'%';$('#barB').style.height=(100-share)+'%'},70);let n=0;const timer=setInterval(()=>{n=Math.min(1,n+.07);$('#scoreA').textContent=fmt(Math.round(A*n))+' cheers';$('#scoreB').textContent=fmt(Math.round(B*n))+' cheers';if(n===1){clearInterval(timer);const win=A===B?'It is a dead heat. Diplomacy wins.':(A>B?a:b)+' takes the belt by '+fmt(Math.abs(A-B))+' cheers.';$('#verdict').innerHTML='<span class="winner">VERDICT:</span> '+win+' The crowd is now unnecessarily invested.'}},35)}
$('#go').addEventListener('click',duel);$('#random').addEventListener('click',()=>{const p=pairs[Math.floor(Math.random()*pairs.length)];$('#left').value=p[0];$('#right').value=p[1];duel()});document.addEventListener('keydown',e=>{if(e.key==='Enter')duel()});duel();
</script>
</body></html>
